struct SingleStageLeachingBalanceEngine: Sendable { func calculate(_ input: SingleStageLeachingBalanceInput) throws -> SingleStageLeachingBalanceResult { let v=[input.drySolidMass,input.initialSoluteOnSolid,input.solventMass,input.leachingDistributionCoefficient,input.solventRetentionPerDrySolid]; guard v.allSatisfy(\.isFinite) else { throw SingleStageLeachingBalanceError.nonFiniteInput }; guard input.drySolidMass>0,input.solventMass>0 else { throw SingleStageLeachingBalanceError.nonPositiveMass }; guard input.initialSoluteOnSolid>0,input.leachingDistributionCoefficient>0 else { throw SingleStageLeachingBalanceError.invalidLoadingOrCoefficient }; guard input.solventRetentionPerDrySolid>=0 else { throw SingleStageLeachingBalanceError.invalidRetention }; let retained=input.drySolidMass*input.solventRetentionPerDrySolid; guard retained<=input.solventMass else { throw SingleStageLeachingBalanceError.retentionExceedsSolvent }; let free=input.solventMass-retained; let initial=input.drySolidMass*input.initialSoluteOnSolid; let ef=input.leachingDistributionCoefficient*input.solventMass/input.drySolidMass; let frac=ef/(1+ef); let ext=initial*frac; let rem=initial-ext; guard [retained,free,initial,ef,frac,ext,rem].allSatisfy(\.isFinite),frac>0,frac<1 else { throw SingleStageLeachingBalanceError.numericalFailure }; return .init(initialSoluteMass:initial,extractedSoluteMass:ext,retainedSoluteMass:rem,extractionFraction:frac,freeExtractSolutionMass:free,retainedSolutionMass:retained,modelName:"Single-stage ideal leaching balance",limitationDescription:"Uses a lumped distribution coefficient and specified solution retention.") } }
